import argparseimport jsonfrom typing import Dict, Any, Optionalclass ConfigManager:        """Base configuration manager with CLI + JSON support and extensible argument parsing.        Key Features:    - Built-in --config argument for JSON file loading    - Extensible CLI arguments via register_argument()    - Priority: CLI > JSON > Defaults    """        def __init__(self):        self._defaults = {}     # default values        self.customs = {}       # customized values        self._config = None                self._parser = self._init_base_parser()        self._register_core_arguments()  # Register base arguments                self.custom_init()                self._config = self._load_config()            def custom_init(self):        """Child class should override if more things need to be done in initialization        """        pass            def _init_base_parser(self) -> argparse.ArgumentParser:                """Initialize basic argument parser"""                parser = argparse.ArgumentParser(            description="Configuration manager for CLI and JSON arguments")        return parser        def _register_core_arguments(self) -> None:        """Register essential arguments (override in subclasses)"""        pass        def register_argument(        self,        name: str,        arg_type: type,        default: Any,        help_text: str = "",        short_name: Optional[str] = None,          **argparse_kwargs    ) -> None:        """Dynamically register CLI argument with both short and long forms.                Args:            name: Full argument name (e.g. "batch_size" → --batch-size)            arg_type: Python type for argument conversion            default: Default value            help_text: Description for --help            short_name: Single-letter shortcut (e.g. "b" for -b)            **argparse_kwargs: Additional argparse kwargs        """                long_name = f"--{name.replace('_', '-')}"        names = [long_name]                if short_name:            if not short_name.startswith("-"):                short_name = f"-{short_name}"            names.append(short_name)                self._parser.add_argument(            *names,            type=arg_type,            default=default,            help=f"{help_text} (default: {default})",            **argparse_kwargs        )        self._defaults[name] = default            def _load_config(self) -> Dict[str, Any]:                """Load configuration with priority: CLI > JSON > Defaults"""                # Parse known CLI args (ignore unrecognized)        cli_args, unknown_args = self._parser.parse_known_args()                if unknown_args:            raise ValueError(f"Unrecognized arguments: {unknown_args}")                cli_params = {            k: v for k, v in vars(cli_args).items()             if v is not None and k != "config"        }                # Load JSON config if specified        json_config = {}        if cli_args.json:            with open(cli_args.json) as f:                json_config = json.load(f)                return {**self._defaults, **json_config, **cli_params, **self.customs}        def get(self, name: str, default: Optional[Any] = None) -> Any:        """                Get parameter value from CLI/JSON/defaults.                Args:            name: Parameter name (snake_case or kebab-case)            default: Fallback value if parameter not found                Returns:            Parameter value if exists, else default                Raises:            KeyError: If parameter not found and no default provided        """                cli_name = name.replace('_', '-')                if self._config is None:            self._config = self._load_config()                try:            return self._config[name]        except KeyError:            try:                return self._config[cli_name]            except KeyError:                if default is not None:                    return default                raise KeyError(f"Parameter '{name}' not found in CLI/JSON/defaults")                                                